function createYieldAccount(address user) public virtual returns (address) {
    require(user != address(0), Errors.INVALID_ADDRESS);
    require(yieldAccounts[user] == address(0), Errors.YIELD_ACCOUNT_ALREADY_EXIST);

    address account = yieldRegistry.createYieldAccount(address(this));
    yieldAccounts[user] = account;
    return account;
}

function createYieldAccount(address user) public virtual override returns (address) {
    super.createYieldAccount(user);

    IYieldAccount yieldAccount = IYieldAccount(yieldAccounts[user]);
    yieldAccount.safeApprove(address(eETH), address(liquidityPool), type(uint256).max);

    return address(yieldAccount);
}

